const CurriculumRow: React.FC<{ subject: string, category: string, hours: number }> = ({ subject, category, hours }) => (
  <tr>
    <td className="px-4 py-4 text-gray-800 font-medium">{subject}</td>
    <td className="px-4 py-4 text-gray-600 text-sm">{category}</td>
