  </tr>
);

export default Curriculum;

import React, { useState } from 'react';
import { sheetsService } from '../services/googleSheetsService';
import { Student, PaymentRecord } from '../types';

const Students: React.FC = () => {
  const [searchNis, setSearchNis] = useState('');
  const [student, setStudent] = useState<Student | null>(null);
  const [payments, setPayments] = useState<PaymentRecord[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const handleSearch = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!searchNis) return;

    setLoading(true);
    setError('');
    setStudent(null);
    setPayments([]);

    try {
      const result = await sheetsService.getStudentByNis(searchNis);
      if (result) {
        setStudent(result);
        const payHistory = await sheetsService.getPayments(searchNis);
        setPayments(payHistory);
      } else {
        setError('NIS tidak ditemukan dalam basis data.');
      }
    } catch (err) {
      setError('Terjadi kesalahan saat mengambil data.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="container mx-auto px-4 py-12 max-w-5xl">
      <div className="text-center mb-12">
        <h1 className="text-4xl font-bold text-[#1a3a5a]">Portal Siswa</h1>
        <p className="text-gray-500 mt-2">Cek data diri dan status administrasi SPP secara real-time.</p>
      </div>

      <div className="bg-white p-8 rounded-2xl shadow-lg border border-gray-100 mb-12">
        <h2 className="text-xl font-bold text-[#1a3a5a] mb-6 flex items-center">
          <svg className="w-6 h-6 mr-2 text-[#f39c12]" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z"></path></svg>
          Pencarian Data Siswa
        </h2>
        <form onSubmit={handleSearch} className="flex flex-col md:flex-row gap-4">
          <input
            type="text"
            placeholder="Masukkan NIS (Contoh: 2024001)"
            value={searchNis}
            onChange={(e) => setSearchNis(e.target.value)}
            className="flex-grow px-6 py-4 rounded-xl bg-gray-50 border focus:outline-none focus:ring-2 focus:ring-[#f39c12] transition"
          />
          <button 
            type="submit"
            disabled={loading}
            className="bg-[#1a3a5a] text-white px-10 py-4 rounded-xl font-bold hover:bg-slate-800 transition disabled:opacity-50"
          >
            {loading ? 'Mencari...' : 'Cari Data'}
          </button>
        </form>
        {error && <p className="text-red-500 mt-4 text-sm font-medium">{error}</p>}
      </div>

      {student && (
        <div className="grid md:grid-cols-3 gap-8 animate-fadeIn">
          {/* Profile Side */}
          <div className="md:col-span-1">
            <div className="bg-[#1a3a5a] text-white p-8 rounded-2xl">
              <div className="w-24 h-24 bg-white/20 rounded-full flex items-center justify-center text-4xl font-bold mb-4 mx-auto">
                {student.name.charAt(0)}
              </div>
              <h3 className="text-xl font-bold text-center">{student.name}</h3>
              <p className="text-center text-white/60 text-sm mb-6">NIS: {student.nis}</p>

              <div className="space-y-4 border-t border-white/10 pt-6 text-sm">
                <div className="flex justify-between">
                  <span className="text-white/60">Kelas</span>
                  <span className="font-bold">{student.class}</span>
                </div>
                <div className="flex justify-between">
                  <span className="text-white/60">Jurusan</span>
                  <span className="font-bold">{student.major}</span>
                </div>
                <div className="flex justify-between">
                  <span className="text-white/60">Status</span>
                  <span className="bg-green-500 px-2 py-0.5 rounded text-[10px] font-black uppercase">Aktif</span>
                </div>
              </div>
            </div>
          </div>

          {/* Payment History Main */}
          <div className="md:col-span-2">
            <div className="bg-white p-8 rounded-2xl shadow-sm border border-gray-100">
              <h3 className="text-xl font-bold text-[#1a3a5a] mb-6">Laporan Pembayaran Siswa</h3>
              <div className="overflow-x-auto">
                <table className="w-full text-left">
                  <thead>
                    <tr className="border-b">
                      <th className="pb-4 text-sm font-bold text-gray-400">Bulan Tagihan</th>
                      <th className="pb-4 text-sm font-bold text-gray-400 text-right">Nominal</th>
                      <th className="pb-4 text-sm font-bold text-gray-400 text-center">Status</th>
                      <th className="pb-4 text-sm font-bold text-gray-400 text-right">Tgl Bayar</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y">
                    {payments.length > 0 ? (
                      payments.map((p, idx) => (
                        <tr key={idx} className="hover:bg-gray-50">
                          <td className="py-4 font-medium">{p.month}</td>
                          <td className="py-4 text-right">Rp {p.amount.toLocaleString('id-ID')}</td>
                          <td className="py-4 text-center">
                            <span className={`px-3 py-1 rounded-full text-xs font-bold ${
                              p.status === 'Lunas' ? 'bg-green-100 text-green-600' : 'bg-red-100 text-red-600'
                            }`}>
                              {p.status}
                            </span>
                          </td>
                          <td className="py-4 text-right text-gray-500 text-sm">{p.datePaid || '-'}</td>
                        </tr>
                      ))
                    ) : (
                      <tr>
                        <td colSpan={4} className="py-10 text-center text-gray-400 italic">Belum ada data pembayaran yang tercatat.</td>
                      </tr>
                    )}
                  </tbody>
                </table>
              </div>
              <div className="mt-8 p-4 bg-orange-50 rounded-lg text-sm text-orange-700">
                <strong>Catatan:</strong> Data diperbarui secara real-time dari Google Sheets Bagian Tata Usaha. Hubungi TU jika terdapat selisih data.
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

