      if (result) {
        setStudent(result);
        const payHistory = await sheetsService.getPayments(nisInput);
        setPayments(payHistory);
      } else {
        setError('NIS tidak ditemukan. Pastikan NIS benar atau hubungi Bagian Tata Usaha.');
